// supabase/functions/persona-eval/index.ts
//
// Eval harness for personas (the 150 canonical specialists).
//
// Flow:
//   1. Find or create an `agent_evals` definition for this persona
//      (a "baseline" eval with N test prompts generated by Claude Opus
//      against the persona's home_team and persona_md).
//   2. Have the persona answer each test prompt using its own model_ref.
//   3. Have Claude Opus (judge) score each answer across a rubric:
//        voice_consistency / domain_depth / actionability / non_duplication
//   4. Aggregate to mean score, decide passed = mean >= threshold.
//   5. INSERT agent_eval_runs row (eval_id, output jsonb, passed).
//   6. Update personas.baseline_eval_run_id and quality_score.
//
// Auth: requires Supabase service_role JWT.
// Body: { persona_slug: string, num_questions?: number, threshold?: number,
//         create_baseline_if_missing?: boolean }

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL") || "";
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || "";
const ANTHROPIC_API_KEY = Deno.env.get("ANTHROPIC_API_KEY") || "";
const DEEPSEEK_API_KEY = Deno.env.get("DEEPSEEK_API_KEY") || "";

const JUDGE_MODEL = "claude-opus-4-7";
const ANTHROPIC_VERSION = "2023-06-01";
const DEFAULT_NUM_QUESTIONS = 4;
const DEFAULT_THRESHOLD = 0.65;
const MAX_ANSWER_TOKENS = 700;
const MAX_PERSONA_MD_CHARS = 6000;

const RUBRIC_CRITERIA = ["voice_consistency", "domain_depth", "actionability", "non_duplication"] as const;

interface EvalRequest {
  persona_slug: string;
  num_questions?: number;
  threshold?: number;
  create_baseline_if_missing?: boolean;
}

interface PersonaRow {
  id: string;
  slug: string;
  name: string;
  role: string | null;
  home_team: string;
  persona_md: string;
  model_ref: string | null;
}

interface RubricScore {
  voice_consistency: number;
  domain_depth: number;
  actionability: number;
  non_duplication: number;
  notes?: string;
}

interface ProbeOutcome {
  question: string;
  answer: string;
  scores: RubricScore;
  mean: number;
}

function json(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), { status, headers: { "Content-Type": "application/json" } });
}

function requireServiceRole(req: Request): Response | null {
  const auth = req.headers.get("Authorization") || "";
  const token = auth.replace(/^Bearer\s+/, "");
  try {
    const payload = JSON.parse(atob(token.split(".")[1] ?? ""));
    if (payload?.role !== "service_role") return json({ error: "service_role required" }, 401);
  } catch { return json({ error: "invalid token" }, 401); }
  return null;
}

async function callClaude(system: string, user: string, maxTokens: number): Promise<{ text: string; tokens_in?: number; tokens_out?: number } | { error: string }> {
  const resp = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json", "x-api-key": ANTHROPIC_API_KEY, "anthropic-version": ANTHROPIC_VERSION },
    body: JSON.stringify({ model: JUDGE_MODEL, max_tokens: maxTokens, system, messages: [{ role: "user", content: user }] }),
  });
  if (!resp.ok) return { error: `Anthropic ${resp.status}: ${await resp.text()}` };
  const data = await resp.json();
  const block = (data.content ?? []).find((b: { type: string }) => b.type === "text");
  return { text: (block?.text ?? "").trim(), tokens_in: data.usage?.input_tokens, tokens_out: data.usage?.output_tokens };
}

async function callDeepseek(model: string, system: string, user: string, maxTokens: number): Promise<{ text: string } | { error: string }> {
  if (!DEEPSEEK_API_KEY) return { error: "DEEPSEEK_API_KEY not set" };
  const resp = await fetch("https://api.deepseek.com/v1/chat/completions", {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${DEEPSEEK_API_KEY}` },
    body: JSON.stringify({ model, max_tokens: maxTokens, temperature: 0.7,
      messages: [{ role: "system", content: system }, { role: "user", content: user }] }),
  });
  if (!resp.ok) return { error: `DeepSeek ${resp.status}: ${await resp.text()}` };
  const data = await resp.json();
  return { text: (data.choices?.[0]?.message?.content ?? "").trim() };
}

async function answerAsPersona(persona: PersonaRow, question: string): Promise<string | null> {
  const system = persona.persona_md.slice(0, MAX_PERSONA_MD_CHARS);
  const user = `${question}\n\nResponda em 2-4 parágrafos, com substância e voz característica sua. Não use bullet burocrático.`;
  const model = persona.model_ref ?? "deepseek-chat";
  const result = model.startsWith("claude")
    ? await callClaude(system, user, MAX_ANSWER_TOKENS)
    : await callDeepseek(model, system, user, MAX_ANSWER_TOKENS);
  if ("error" in result) { console.error(`answer failed: ${result.error}`); return null; }
  return result.text || null;
}

async function generateTestPrompts(persona: PersonaRow, n: number): Promise<string[]> {
  const userPrompt = `Persona alvo: ${persona.name} (${persona.role ?? ""}), home_team=${persona.home_team}.\n\nFragmento do persona_md:\n${persona.persona_md.slice(0, 3500)}\n\nGere ${n} perguntas executivas (CEO/diretor) que testam essa persona no seu core. Mistura:\n- 50% perguntas de decisão concreta no domínio dela\n- 30% perguntas adjacentes que ela tem opinião forte\n- 20% perguntas onde ela deveria DISCORDAR de algum framing\n\nRetorne JSON array de strings, sem markdown, sem numeração. Cada pergunta ≤ 30 palavras.`;

  const result = await callClaude("Você é um avaliador rigoroso de personas executivas.", userPrompt, 1500);
  if ("error" in result) { console.error(`test prompt gen failed: ${result.error}`); return []; }
  const text = result.text;
  const start = text.indexOf("[");
  const end = text.lastIndexOf("]");
  if (start < 0 || end < 0) return [];
  try {
    const arr = JSON.parse(text.slice(start, end + 1));
    return Array.isArray(arr) ? arr.filter((q): q is string => typeof q === "string") : [];
  } catch { return []; }
}

async function judgeAnswer(persona: PersonaRow, question: string, answer: string): Promise<RubricScore | null> {
  const system = `Você é um juiz rigoroso da fidelidade de uma persona. Avalie a resposta abaixo contra a persona declarada, retornando JSON com 4 scores (0.0 a 1.0) e uma nota curta:

{
  "voice_consistency": <0-1, soou como a persona? signature phrases, registro, vocabulário?>,
  "domain_depth": <0-1, mostra expertise real no domínio dela? cita conceitos não-genéricos?>,
  "actionability": <0-1, recomendações concretas e acionáveis? ou conselho de fortune cookie?>,
  "non_duplication": <0-1, adiciona substância? ou repete a pergunta com palavras diferentes?>,
  "notes": "<1-2 frases justificando>"
}

Regras: penalize voz vaga, mesmo que correta tecnicamente. Premie quando a persona ousa discordar do framing. Apenas JSON, sem markdown.`;

  const userPrompt = `PERSONA: ${persona.name}\nROLE: ${persona.role ?? ""}\nHOME_TEAM: ${persona.home_team}\n\nFRAGMENTO DO PERSONA_MD (referência de voz):\n${persona.persona_md.slice(0, 3000)}\n\nPERGUNTA:\n${question}\n\nRESPOSTA DA PERSONA:\n${answer}\n\nProduza o JSON conforme especificado.`;

  const result = await callClaude(system, userPrompt, 600);
  if ("error" in result) { console.error(`judge failed: ${result.error}`); return null; }
  const text = result.text;
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");
  if (start < 0 || end < 0) return null;
  try {
    const parsed = JSON.parse(text.slice(start, end + 1));
    const score: RubricScore = {
      voice_consistency: Number(parsed.voice_consistency ?? 0),
      domain_depth: Number(parsed.domain_depth ?? 0),
      actionability: Number(parsed.actionability ?? 0),
      non_duplication: Number(parsed.non_duplication ?? 0),
      notes: parsed.notes ?? "",
    };
    return score;
  } catch { return null; }
}

function meanRubric(s: RubricScore): number {
  return (s.voice_consistency + s.domain_depth + s.actionability + s.non_duplication) / 4;
}

Deno.serve(async (req) => {
  if (req.method !== "POST") return new Response("Method not allowed", { status: 405 });
  const denied = requireServiceRole(req); if (denied) return denied;
  if (!ANTHROPIC_API_KEY) return json({ error: "ANTHROPIC_API_KEY not set" }, 503);

  const body: EvalRequest = await req.json().catch(() => ({ persona_slug: "" }) as EvalRequest);
  if (!body.persona_slug) return json({ error: "persona_slug required" }, 400);

  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

  const { data: persona, error: pErr } = await supabase
    .from("personas")
    .select("id, slug, name, role, home_team, persona_md, model_ref")
    .eq("slug", body.persona_slug).eq("status", "canonical").single();
  if (pErr || !persona) return json({ error: `persona '${body.persona_slug}' not found: ${pErr?.message}` }, 404);

  const numQuestions = body.num_questions ?? DEFAULT_NUM_QUESTIONS;
  const threshold = body.threshold ?? DEFAULT_THRESHOLD;

  // 1) Find or create a baseline eval definition
  let evalRow: { id: string; input_payload: Record<string, unknown> } | null = null;
  const { data: existing } = await supabase
    .from("agent_evals")
    .select("id, input_payload")
    .eq("persona_id", persona.id).eq("slug", `eval-${persona.slug}-baseline`).maybeSingle();
  if (existing) {
    evalRow = existing as { id: string; input_payload: Record<string, unknown> };
  } else if (body.create_baseline_if_missing !== false) {
    const questions = await generateTestPrompts(persona as PersonaRow, numQuestions);
    if (questions.length === 0) return json({ error: "could not generate test prompts" }, 500);
    const rubric = { criteria: RUBRIC_CRITERIA, weights: { voice_consistency: 0.25, domain_depth: 0.25, actionability: 0.25, non_duplication: 0.25 }, judge_model: JUDGE_MODEL };
    const inputPayload = { questions };
    const { data: created, error: cErr } = await supabase
      .from("agent_evals")
      .insert({
        slug: `eval-${persona.slug}-baseline`,
        title: `Baseline eval for ${persona.name}`,
        persona_id: persona.id,
        input_type: "prompt",
        input_payload: inputPayload,
        rubric,
        status: "active",
      })
      .select("id, input_payload").single();
    if (cErr || !created) return json({ error: `agent_evals create failed: ${cErr?.message}` }, 500);
    evalRow = created as { id: string; input_payload: Record<string, unknown> };
  } else {
    return json({ error: "no baseline eval defined and create_baseline_if_missing=false" }, 404);
  }

  // 2) Run the eval — persona answers + judge scores
  const questions = (evalRow.input_payload?.questions ?? []) as string[];
  if (questions.length === 0) return json({ error: "eval has no questions" }, 500);

  const outcomes: ProbeOutcome[] = [];
  for (const q of questions) {
    const answer = await answerAsPersona(persona as PersonaRow, q);
    if (!answer) continue;
    const scores = await judgeAnswer(persona as PersonaRow, q, answer);
    if (!scores) continue;
    outcomes.push({ question: q, answer, scores, mean: meanRubric(scores) });
  }
  if (outcomes.length === 0) return json({ error: "no usable outcomes" }, 500);

  const mean = outcomes.reduce((s, o) => s + o.mean, 0) / outcomes.length;
  const meansByCriterion = {
    voice_consistency: outcomes.reduce((s, o) => s + o.scores.voice_consistency, 0) / outcomes.length,
    domain_depth: outcomes.reduce((s, o) => s + o.scores.domain_depth, 0) / outcomes.length,
    actionability: outcomes.reduce((s, o) => s + o.scores.actionability, 0) / outcomes.length,
    non_duplication: outcomes.reduce((s, o) => s + o.scores.non_duplication, 0) / outcomes.length,
  };
  const passed = mean >= threshold;

  // 3) INSERT agent_eval_runs
  const output = {
    persona_slug: persona.slug,
    model_used: persona.model_ref ?? "deepseek-chat",
    judge_model: JUDGE_MODEL,
    threshold,
    mean,
    means_by_criterion: meansByCriterion,
    num_probes: outcomes.length,
    outcomes,
  };
  const { data: runRow, error: rErr } = await supabase
    .from("agent_eval_runs")
    .insert({ eval_id: evalRow.id, output, passed })
    .select("id").single();
  if (rErr || !runRow) return json({ error: `agent_eval_runs insert failed: ${rErr?.message}` }, 500);

  // 4) Update persona baseline + quality_score (lifecycle hook)
  await supabase.from("personas")
    .update({ baseline_eval_run_id: runRow.id, quality_score: mean, updated_at: new Date().toISOString() })
    .eq("id", persona.id);

  return json({
    persona_slug: persona.slug,
    eval_id: evalRow.id,
    eval_run_id: runRow.id,
    threshold, mean, passed,
    means_by_criterion: meansByCriterion,
    num_probes: outcomes.length,
    judge_model: JUDGE_MODEL,
    model_used: persona.model_ref ?? "deepseek-chat",
  });
});
